/// The binding-proof context string the HMAC was computed over. Pallet
/// verifies byte-identically against what the ceremony used.
pub const BINDING_PROOF_CONTEXT: &[u8] = b"zkpki-binding-proof-v1";

/// Expected commitment bytes: `blake2b_256(hmac_output || challenge)`.
/// Pre-computed off-device (Python `hashlib.blake2b` with digest_size=32)
/// so the parser's commitment computation can be asserted against a
/// ground-truth value rather than just "signature verifies" (which would
/// also pass if the parser hashed the wrong thing with the same curve).
pub const EXPECTED_COMMITMENT: [u8; 32] = [
    0xaf, 0x36, 0x7b, 0xe8, 0x4c, 0x8c, 0xf0, 0xe6,
    0x10, 0x81, 0x1a, 0x27, 0x77, 0x0c, 0x5c, 0x10,
    0xa8, 0xe3, 0xe8, 0x59, 0x56, 0x0a, 0x54, 0xbf,
    0x2f, 0x31, 0x99, 0x97, 0x0d, 0xaa, 0xf9, 0x6b,
];

/// Helper: decode a hex string (may contain whitespace) into bytes.
pub fn hex_to_bytes(s: &str) -> Vec<u8> {
    let cleaned: String = s.chars().filter(|c| !c.is_whitespace()).collect();
    (0..cleaned.len())
        .step_by(2)
        .map(|i| u8::from_str_radix(&cleaned[i..i + 2], 16).expect("valid hex"))
        .collect()
}

pub fn challenge() -> Vec<u8> { hex_to_bytes(CHALLENGE_HEX) }
pub fn cert_ec_leaf() -> Vec<u8> { hex_to_bytes(CERT_EC_LEAF_HEX) }
pub fn cert_ec_int1() -> Vec<u8> { hex_to_bytes(CERT_EC_INT1_HEX) }
pub fn cert_ec_int2() -> Vec<u8> { hex_to_bytes(CERT_EC_INT2_HEX) }
pub fn cert_ec_root() -> Vec<u8> { hex_to_bytes(CERT_EC_ROOT_HEX) }
pub fn attest_ec_leaf() -> Vec<u8> { hex_to_bytes(ATTEST_EC_LEAF_HEX) }
pub fn hmac_binding_output() -> Vec<u8> { hex_to_bytes(HMAC_BINDING_OUTPUT_HEX) }
pub fn binding_signature() -> Vec<u8> { hex_to_bytes(BINDING_SIGNATURE_HEX) }

/// Full cert_ec chain (leaf + 2 intermediates + root).
pub fn cert_ec_chain() -> Vec<Vec<u8>> {
    vec![cert_ec_leaf(), cert_ec_int1(), cert_ec_int2(), cert_ec_root()]
}

/// Full attest_ec chain. The leaf is different from cert_ec_leaf; the
/// intermediates and root are byte-identical because they were
/// provisioned onto this device at manufacture time and are shared across
/// all keys attested on this hardware.
pub fn attest_ec_chain() -> Vec<Vec<u8>> {
    vec![attest_ec_leaf(), cert_ec_int1(), cert_ec_int2(), cert_ec_root()]
}
